window.bookAuthor = function(book, locale) {
  const L = locale || window.__lg_locale || "en";
  const map = window.LG_BOOK_AUTHORS[book.id];
  if (map && map[L]) return map[L];
  if (map && map.en) return map.en;
  return book.author;
};
